export const meta = {
  name: 'claims-remaining-gap-analysis',
  description: 'Exhaustive, adversarially-verified gap analysis: what remains before live API testing and before the take-home is submission-ready',
  phases: [
    { title: 'Audit', detail: '5 parallel read-only auditors across runnability, README fidelity, deliverable docs, JSONL trail, PRD conformance' },
    { title: 'Verify', detail: 'Adversarially re-check each claimed blocker against the actual files to kill false positives' },
  ],
}

// ---- Shared context handed to every agent. Agents MUST verify against real files, not trust this. ----
const REPO = '/Users/raunaksingh/Documents/realfast/insurance'
const CONTEXT = `
Repo root: ${REPO}. This is a 24-48h take-home: a health-insurance Claims Processing System.
Stack: TypeScript strict + Node, Fastify, better-sqlite3 + drizzle, vitest, biome, pnpm.

ESTABLISHED FACTS (already verified by the lead — re-verify if your finding depends on them):
- The pure domain engine + repositories + services + Fastify route HANDLERS are complete.
- 63/63 vitest tests pass across 15 files, incl. 12 HTTP tests that drive routes IN-PROCESS via app.inject() (no live server).
- Git tree is CLEAN, 46 commits with granular test:/feat: pairs (TDD history visible).
- KNOWN STUBS (one-line files, no real code): app/src/index.ts, app/src/db/seed.ts, app/src/config/env.ts, app/src/docs/openapi.ts.
- package.json scripts are ONLY: test, test:watch, typecheck, lint, format. There is NO dev/start/seed/migrate script.
- app/src/db/connection.ts (createDb factory, file or :memory:) and app/src/db/migrate.ts (applySchema from schema.sql) are REAL and complete.
- README.md tells a reviewer to run \`pnpm seed\` and \`pnpm dev\` and to curl localhost:3000.
- No app/rules/*.json data files exist (seed.ts comment says it reads them).
- The assignment (project-docs/problem_statement.md + project-docs/candidate_assignment_instructions.md) requires, as HARD rejection triggers: a clone-and-run working app; README that runs; docs/domain-model.md, docs/decisions.md, docs/self-review.md; and RAW .jsonl session logs covering EVERY phase (framing, research, planning, coding, docs, testing, QA).
- PRD.md is the locked internal spec (4 routes, 7 in-scope items, 19 documented assumptions incl. #14 "diagnosis_code + provider captured as ENCRYPTED, non-adjudicated PHI").

The user's immediate next step is LIVE API TESTING (curl/Postman against a running server with seeded data).
Read excerpts, cite file:line. Be concrete and concise. Do NOT run builds or tests (the lead handles that). Read-only.
`

const BLOCKER_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['area', 'summary', 'findings'],
  properties: {
    area: { type: 'string' },
    summary: { type: 'string', description: 'one-sentence headline for this area' },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['title', 'severity', 'blocks', 'evidence', 'fix'],
        properties: {
          title: { type: 'string' },
          severity: { type: 'string', enum: ['blocker', 'major', 'minor', 'ok'] },
          blocks: { type: 'string', enum: ['api-testing', 'submission', 'both', 'none'], description: 'what this gap blocks' },
          evidence: { type: 'string', description: 'file:line + what you actually saw' },
          fix: { type: 'string', description: 'concrete, minimal action to close it' },
        },
      },
    },
  },
}

const VERIFY_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['verdicts'],
  properties: {
    verdicts: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['title', 'standsUp', 'severityAfterCheck', 'note'],
        properties: {
          title: { type: 'string' },
          standsUp: { type: 'boolean', description: 'true if the finding is real after adversarial re-check' },
          severityAfterCheck: { type: 'string', enum: ['blocker', 'major', 'minor', 'ok', 'false-positive'] },
          note: { type: 'string', description: 'what you re-checked and why the verdict' },
        },
      },
    },
  },
}

const DIMENSIONS = [
  {
    key: 'runnability',
    prompt: `${CONTEXT}
YOUR AREA: Runnability / live-server bootstrap. The user wants to start a real server and curl it.
Determine EXACTLY what is missing to (a) start a live Fastify server on a port over a file-backed SQLite DB, and (b) load seed data so endpoints return something.
Check: app/src/index.ts, app/src/db/seed.ts, app/src/config/env.ts, app/src/app.ts, connection.ts, migrate.ts, app/src/db/schema.sql (does it exist?), package.json scripts, and whether ANY alternate entrypoint/bootstrap exists (grep for listen(, buildApp(, createDb( usage outside tests). Confirm whether the wiring graph (db -> repos -> services -> controllers -> routes) can be assembled outside tests today.
List the concrete, ordered tasks needed to make \`<some command>\` start a seeded, queryable API. Note where coverage-rule seed data must come from (JSON files? inline? a seedWorld equivalent?).`,
  },
  {
    key: 'readme-fidelity',
    prompt: `${CONTEXT}
YOUR AREA: README clone-and-run fidelity — the assignment's #1 rejection trigger ("we clone and run from your README; if it doesn't run, the review stops").
Read README.md line by line and cross-check EVERY command and curl example against reality: do \`pnpm seed\`/\`pnpm dev\` scripts exist in package.json? Do the curl service codes (e.g. OFFICE_VISIT) exist in the closed 12-code catalog (check app/src/domain/... reason-codes / coverage-rule / a catalog constant)? Do the ids (m_001, clm_001, li_002) match anything seeded? Does the request body shape (serviceDate per line-item vs claim-level) match submit-claim.schema.ts and the service input type? Is the Node engine claim consistent (README says 20+, package.json engines says?)?
Output every inaccuracy a reviewer would hit on first run, each with the exact fix.`,
  },
  {
    key: 'deliverable-docs',
    prompt: `${CONTEXT}
YOUR AREA: Required deliverable docs — present, substantive, and HONEST (self-review must match reality).
Read docs/domain-model.md, docs/decisions.md, docs/self-review.md (and skim docs/problem-statement-coverage.md). For each: present? substantive (not a stub)? aligned with the actual shipped code?
CRITICAL honesty checks — does docs/self-review.md (or decisions.md) openly acknowledge: (1) the app is NOT runnable yet / no server bootstrap / no seed / README commands don't exist; (2) PHI (diagnosis_code, provider) is documented as "encrypted at rest" but check claim.service.ts / repositories / schema.sql — is it ACTUALLY encrypted, or stored plaintext? If plaintext, is that gap disclosed? A self-review that claims completeness the code doesn't have is a rejection trigger.
Output what's solid vs thin/stale/misaligned, with the minimal fix for each.`,
  },
  {
    key: 'jsonl-trail',
    prompt: `${CONTEXT}
YOUR AREA: Raw .jsonl session-log coverage — a HARD, non-negotiable rejection trigger if any phase is missing.
Inventory ai-artifacts/ : which of the 7 phases (01-framing, 02-domain-research, 03-design, 04-coding, 05-testing, 06-docs, 07-qa) actually contain a .jsonl file vs only .md/.gitkeep? Read ai-artifacts/README.md if present. Note: the lead found only 01-framing has a .jsonl.
State exactly which phases are missing JSONL, quote the assignment's rejection language, and describe the concrete remediation (where Claude Code stores session transcripts and that they must be exported per phase into ai-artifacts/{phase}/). Severity = blocker for submission.`,
  },
  {
    key: 'prd-conformance',
    prompt: `${CONTEXT}
YOUR AREA: PRD / problem-statement conformance of the SHIPPED code (engine + API response shapes). The engine is well-tested; hunt for DIVERGENCES between documented claims and actual behavior that would surprise the user during API testing.
Check against PRD.md and project-docs/problem_statement.md:
- The 4 routes exist & are wired (routes/claims.routes.ts) — confirm.
- GET /claims/:id response shape (claim-read.service.ts ClaimSnapshot): does it include the timeline? Does it expose dispute history / adjudication_history / disputes[]? PRD route table requires "line items, statuses, payable amounts, and the timeline" — is anything PROMISED but missing, or present but undocumented?
- Dispute endpoint: does the response surface the 4-value outcome (UPHELD|OVERTURNED|PARTIALLY_OVERTURNED|MODIFIED) and the preserved original? (dispute.controller.ts / dispute.service.ts)
- Accumulator carry-forward across claims: demonstrable via the API with seeded data? (relevant to whether a reviewer can SEE limits exhaust)
- NEEDS_REVIEW / UNDER_REVIEW states: reachable only via dispute — consistent in code?
- Validation/error mapping: intake reject -> 4xx with {errors:[...]}; adjudication denial -> 200 with reason code. Confirm controllers + schemas match.
Output divergences and any PRD claim the code does not honor, each with severity and fix.`,
  },
]

phase('Audit')

// Pipeline: each dimension is audited, then its OWN findings are adversarially re-checked the moment that audit returns.
const audited = await pipeline(
  DIMENSIONS,
  (d) => agent(d.prompt, { label: `audit:${d.key}`, phase: 'Audit', schema: BLOCKER_SCHEMA }),
  (report, d) => {
    if (!report || !report.findings || report.findings.length === 0) return { report, verify: null }
    const list = report.findings
      .map((f, i) => `${i + 1}. [${f.severity}/${f.blocks}] ${f.title} — evidence: ${f.evidence}`)
      .join('\n')
    return agent(
      `${CONTEXT}
ADVERSARIAL VERIFICATION for area "${d.key}". Another agent produced these findings. Your job is to REFUTE each one by checking the actual files. Default to skepticism: if a finding is wrong, overstated, or already mitigated somewhere, mark standsUp=false. If it is real, confirm severity. Do NOT invent new findings; only judge these:
${list}`,
      { label: `verify:${d.key}`, phase: 'Verify', schema: VERIFY_SCHEMA },
    ).then((v) => ({ report, verify: v }))
  },
)

return audited.filter(Boolean).map((x) => ({
  area: x.report?.area,
  summary: x.report?.summary,
  findings: x.report?.findings ?? [],
  verdicts: x.verify?.verdicts ?? [],
}))

